import { Col, Form, Input, Row, Space, Upload } from "antd"
import { useState } from "react"
import CustomModal from "src/components/Modal/CustomModal"
import ButtonCustom from "src/components/MyButton/Button"
import notice from "src/components/Notice"
import SvgIcon from "src/components/SvgIcon"
import { getRegexEmail, getRegexMobile } from "src/lib/stringsUtils"
import ContactService from "src/services/ContactService"
import FileService from "src/services/FileService"
import styled from "styled-components"
const Styled = styled.div`
  border-radius: 8px;
  padding: 0px 16px;
  .ant-form-item {
    margin-bottom: 0px !important;
  }
`
const { TextArea } = Input

const AddQuestionModal = ({ open, onCancel, customerInfo, onOk, getList }) => {
  const [loading, setLoading] = useState(false)
  const [form] = Form.useForm()
  const [fileList, setFileList] = useState([])
  // useEffect(() => {
  //   onSubmit()
  // }, [])
  const handleFileChange = ({ fileList: newFileList }) => {
    setFileList(newFileList)
  }
  const handleFileRemove = file => {
    const updatedFileList = fileList.filter(item => item.uid !== file.uid)
    setFileList(updatedFileList)
  }
  const onSubmit = async () => {
    try {
      const formData = new FormData()
      setLoading(true)
      const values = await form.validateFields()
      const res = await ContactService.sendContact({
        ...values,
      })
      if (res?.isError) return
      let resUpload
      if (fileList.length > 0) {
        formData.append("InsertFileList", fileList[0]?.originFileObj)
        formData.append("GuidID", res?.Object?.ContactID)
        const resFile = await FileService.uploadFileList(formData)
        if (resFile.isError) return
        setFileList([])
      }
      notice({
        msg: "Gửi yêu cầu thành công ! Chúng tôi sẽ liên hệ sớm với bạn.",
      })
      form.resetFields()
      getList()
      onCancel()
    } finally {
      setLoading(false)
    }
  }
  const footer = (
    <Space className="d-flex justify-content-flex-end">
      <ButtonCustom
        loading={loading}
        btnType="primary"
        onClick={() => onSubmit()}
      >
        Gửi
      </ButtonCustom>
    </Space>
  )

  return (
    <CustomModal
      footer={footer}
      open={!!open}
      onCancel={onCancel}
      title="Yêu cầu hỗ trợ"
      width={700}
    >
      <Form form={form} layout="vertical">
        <Styled>
          <Row>
            <Col md={24} xs={24} className="p-5">
              <Row gutter={[20, 8]}>
                <Col md={24} xs={24}>
                  <Form.Item
                    name="FullName"
                    label="Họ và Tên"
                    required
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống!",
                      },
                    ]}
                  >
                    <Input placeholder="Họ và Tên" />
                  </Form.Item>
                </Col>
                <Col md={24} xs={24}>
                  <Form.Item
                    name="PhoneNumber"
                    label="Số điện thoại"
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống",
                      },
                      {
                        pattern: getRegexMobile(),
                        message:
                          "Số điện thoại là chuỗi từ 8 đến 15 kí tự chữ số",
                      },
                    ]}
                  >
                    <Input placeholder="Số điện thoại" />
                  </Form.Item>
                </Col>

                <Col md={24} xs={24}>
                  <Form.Item
                    name="Address"
                    maxLength={500}
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống!",
                      },
                    ]}
                  >
                    <Input placeholder="Địa chỉ" />
                  </Form.Item>
                </Col>

                <Col md={24} xs={24}>
                  <Form.Item
                    name="Email"
                    label="Email"
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống!",
                      },
                      {
                        pattern: getRegexEmail(),
                        message: "Email sai định dạng",
                      },
                    ]}
                  >
                    <Input placeholder="Email" />
                  </Form.Item>
                </Col>

                <Col md={24} xs={24}>
                  <Form.Item
                    name="Content"
                    label="Nội dung"
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống!",
                      },
                    ]}
                  >
                    <TextArea placeholder="Nội dung" rows={4} />
                  </Form.Item>
                </Col>
                <Col md={24} xs={24}>
                  <Form.Item
                  // name="file"
                  // rules={[
                  //   {
                  //     required: true,
                  //     message: "Vui lòng chọn file",
                  //   },
                  // ]}
                  >
                    <Upload.Dragger
                      fileList={fileList}
                      onChange={handleFileChange}
                      onRemove={handleFileRemove}
                      beforeUpload={() => {
                        return false
                      }}
                    >
                      <div className="d-flex-center" style={{ height: "8px" }}>
                        <div className="mr-8">
                          <SvgIcon name="cloud" />
                        </div>
                        <div>
                          <span>
                            Kéo hoặc{" "}
                            <span style={{ color: "#154398" }}>Chọn File</span>
                          </span>
                        </div>
                      </div>
                    </Upload.Dragger>
                  </Form.Item>
                </Col>
              </Row>
            </Col>
            {/* <Col md={12} xs={0} className="p-5">
              <iframe
                src="https://www.google.com/maps/embed?pb=!1m10!1m8!1m3!1d15726.35347144328!2d105.63611355295369!3d9.800853658087656!3m2!1i1024!2i768!4f13.1!5e0!3m2!1svi!2s!4v1688375230734!5m2!1svi!2s"
                width="100%"
                height="100%"
                style={{
                  border: 0,
                }}
                allowfullscreen=""
                loading="lazy"
                referrerpolicy="no-referrer-when-downgrade"
              ></iframe>
            </Col> */}
          </Row>
        </Styled>
      </Form>
    </CustomModal>
  )
}

export default AddQuestionModal
